mapper.select:
SELECT id, user_id, social_type, social_id, social_name, social_avatar,
       access_token, refresh_token, token_expire_time, bind_time, update_time
FROM sys_social_bind
WHERE social_type = #{socialType}
  AND social_id = #{socialId}
LIMIT 1

SELECT id, user_id, social_type, social_id, social_name, social_avatar,
       access_token, refresh_token, token_expire_time, bind_time, update_time
FROM sys_social_bind
WHERE user_id = #{userId}
  AND social_type = #{socialType}
LIMIT 1

mapper.update:
UPDATE sys_social_bind
social_name = #{socialName}, social_avatar = #{socialAvatar}, access_token = #{accessToken}, refresh_token = #{refreshToken}, token_expire_time = #{tokenExpireTime}, update_time = NOW()
WHERE id = #{id}
